#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUv;
screen3 = vec3 ((vUv-.5)*uAspect.xy,1);//wirkt wie zoom / Tele ###

//*****leaves**********
lav_gnd = texture(sampler_noise_hq,vUv)*.03;
rsl3 = lproject(pos,1.5) + vec3 (q29,-uTime/118,0) + vec3 (mov,0);
float glmask = texture(sampler_pw_noise_lq,rsl3.x*.004) >= .3;
uv2 = rsl3.xy*16;
uv2.y += texture(sampler_pw_noise_lq,uv2.x/256).g*-2*uTime;
vec3 noise = 8*texture(sampler_pw_noise_lq,uv2/256);
lmask = noise.g >= 7.; lmask *= glmask;
uv2 = fract(uv2);
float lside = sin((noise.b-8)*2*uTime+q32);
float lsize = 3*(noise.g-6);
leaves = lmask*lsize *(3+fract(4*uv2.x/uv2.y))/4
        -26*length((uv2-.5)*vec2(1,2/lside));
lcol = (1+texture(sampler_noise_hq,uv2/8+noise))* vec3 (.8+lside/4,.5,0);;
lcol -= texture(sampler_noise_hq,uv2+noise).r*.25;
leaves = clamp01(leaves);

//**** main part ******
lav_gnd = 0;
rsl = project (pos, 1)+vec3 (uTime*.006,.6,0);
back = clamp01(1-rsl.y);
cloud = clamp01(noise2(rsl.xy/8*vec2(1,4))-.4)*clamp01(.5+back);
back *= vec3(.7,.77,.96);
sky = mix(back,2*cloud,cloud/2);
//sky = back;
//sky = back + cloud/4;
ret1 = sky;
lprof2 = 0;
for (n=anz; n >= 1; n--) {
  dist = (n); lav_gnd = 0;  mov += n/anz;
  for (m=1; m <= quality; m++) {
    rsl = project (pos, dist)+vec3 (mov,0);
    lprof =  .5-lum(GetBlur1(fract(rsl.xy))); //mittelwert null !#
    lav_gnd -= lprof/quality*depth/rsl.z;
  }

  rsl = project (pos, dist)+vec3 (mov,0) ;
  rsl2 = project (pos, dist)+vec3 (0,0,0);
  int first = (n==1);
  if (!first) {shadow = clamp01(4*GetPixel(fract(rsl2.xy))) ;}
  neu = GetPixel(fract(rsl.xy));
  float  dista = length(rsl.xy)*.001;
  mask = clamp01(16/dist*lum(neu))*gmask;
  neu *= 1-.5*lum(texture(sampler_noise_lq,rsl.xy*4));
  clshadow = clamp(q20*1.6-noise2(rsl.xy*vec2(.02,.1)+vec2(uTime*.01,0)),.2,1);
  neu *= (1-shadow*.5* (!first))*clshadow;

//  neu *= clamp01(noise2(rsl.xy/16+uTime*.01)+q20-.5+0*(rsl.z)) ; // Abdunkelung hinten
  neu = mix(back, neu, clamp01(5-rsl.z)); //Nebel
    ret1 = mix(ret1,neu,mask) ;
}

rsl = project (pos, dist)+vec3 (mov+lprof/2,0);

ret1 = mix(ret1,leaves*(1-shadow/2)*clshadow*lcol, leaves*.5*clamp01(!mask));
//ret1 *= clshadow;
//ret = 1-exp(-ret1*2+.1) ;
ret = ret1;

//ret = GetPixel(uv0);

  fragColor = ret;
}
